18: // Size rank for each type: higher means larger range. Bool is special (rank -1).
19: function typeRank(t: string): number {
20:   if (t === "U8" || t === "I8") return 1;
21:   if (t === "U16" || t === "I16") return 2;
22:   if (t === "U32" || t === "I32") return 3;
23:   if (t === "F32") return 4;
24:   if (t === "F64") return 5;
25:   if (t === "Bool") return -1;
26:   return 0;
27: }
