32: export function compile(source: string): Ok<string> | Err<CompileError> {
33:   if (source.trim() === "") {
34:     return new Ok(defaultReturn);
35:   }
36:   const reads: string[] = [];
37:   const readExprs: string[] = [];
38: 
39:   for (const type of [
40:     "U8",
41:     "I8",
42:     "U16",
43:     "I16",
44:     "U32",
45:     "I32",
46:     "F32",
47:     "F64",
48:     "Bool",
49:   ]) {
50:     const readExpr = "read<" + type + ">()";
51:     let idx = source.indexOf(readExpr);
52:     while (idx !== -1) {
53:       reads.push(type);
54:       readExprs.push(readExpr);
55:       idx = source.indexOf(readExpr, idx + 1);
56:     }
57:   }
58: 
59:   if (reads.length === 0) {
60:     return (() => {
61:       return compileStatements(source, "", [], 0);
62:     })();
63:   }
64: 
65:   const stdInPart = "stdIn.replace(',', ' ').split(' ')[i] || stdIn";
66:   const parsePrefix = "parse";
67:   let code = "";
68:   let expr = source;
69: 
70:   // Map from generated variable name to its type (e.g. v0 -> U16)
71:   const varTypes: string[] = [];
72: 
73:   for (let i = 0; i < reads.length; i++) {
74:     const type: string | undefined = reads[i];
75:     if (type === undefined) continue;
76:     let parseExpr: string;
77:     const indexBracket = "[" + i + "]";
78:     if (type === "Bool") {
79:       parseExpr = ("(" + stdInPart + ') !== "' + boolFalse + '"').replace(
80:         "[i]",
81:         indexBracket,
82:       );
83:     } else if (type === "F32" || type === "F64") {
84:       parseExpr = (parsePrefix + "Float(" + stdInPart + ")").replace(
85:         "[i]",
86:         indexBracket,
87:       );
88:     } else {
89:       parseExpr = (parsePrefix + "Int(" + stdInPart + ", 10)").replace(
90:         "[i]",
91:         indexBracket,
92:       );
93:     }
94:     code += constKeyword + "v" + i + " = " + parseExpr + ";\n";
95:     varTypes.push(type);
96:     const readExpr: string | undefined = readExprs[i];
97:     if (readExpr === undefined) continue;
98:     expr = expr.replace(readExpr, "v" + i);
99:   }
100: 
101:   // Split by semicolons and process each statement
102:   return compileStatements(expr, code, varTypes, reads.length);
103: }
