105: // Compile source that has no read expressions (e.g. boolean literals)
106: // Shared logic for processing statements after read expressions are replaced
107: function compileStatements(
108:   expr: string,
109:   initialCode: string,
110:   varTypes: string[],
111:   readsCount: number,
112: ): Ok<string> | Err<CompileError> {
113:   let code = initialCode;
114: 
115:   // Split by semicolons and process each statement
116:   const declaredVars: string[] = [];
117:   // Track which variables were declared as mutable
118:   const mutVars: Set<string> = new Set();
119:   // Map variable names to their types (both generated v0..vn and user-declared x, y, etc.)
120:   const allVarTypes: { name: string; type: string }[] = [];
121: 
122:   // Helper: look up the inferred/declared type of a variable by its name
123:   function lookupType(varName: string): string | undefined {
124:     for (let vi = 0; vi < readsCount; vi++) {
125:       if (varName === "v" + vi) return varTypes[vi];
126:     }
127:     for (const entry of allVarTypes) {
128:       if (entry.name === varName) return entry.type;
129:     }
130:     return undefined;
131:   }
132: 
133:   // Shared Ok value for success cases where no payload is needed
134:   const okVoid = new Ok(undefined);
135: 
136:   // Helper: check type compatibility and return Err on mismatch, or okVoid when compatible
137:   function checkAssignable(
138:     srcType: string | undefined,
139:     targetType: string | undefined,
140:   ): Ok<void> | Err<CompileError> {
141:     if (
142:       srcType !== undefined &&
143:       targetType !== undefined &&
144:       !(() => {
145:         const srcRank = typeRank(srcType);
146:         const tgtRank = typeRank(targetType);
147:         if (srcRank === -1 && tgtRank !== -1) return false;
148:         if (tgtRank === -1 && srcRank !== -1) return false;
149:         return srcRank <= tgtRank;
150:       })()
151:     ) {
152:       return new Err(CompileError.TypeMismatch);
153:     }
154:     return okVoid;
155:   }
156: 
157:   // Helper: process an assignment statement and append generated JS code
158:   function emitAssignment(
159:     varName: string,
160:     value: string,
161:     declaredType: string | undefined,
162:     isMutable: boolean,
163:   ): Ok<void> | Err<CompileError> {
164:     let srcType = lookupType(value);
165: 
166:     // Handle bool literals by setting their type explicitly
167:     if (value === boolTrue || value === boolFalse) {
168:       srcType = "Bool";
169:     }
170: 
171:     // Extract type from typed numeric literals like 1U8, 5I32 etc.
172:     const literalType = (() => {
173:       for (const t of ["F64", "F32", "U32", "I32", "U16", "I16", "U8", "I8"]) {
174:         if (value.endsWith(t)) return t;
175:       }
176:       return undefined;
177:     })();
178:     if (literalType !== undefined) {
179:       srcType = literalType;
180:     }
181: 
182:     // Convert Tuff if/else to JS ternary before emitting
183:     const existingType = lookupType(varName);
184:     const assignResult = checkAssignable(
185:       srcType,
186:       declaredType !== undefined ? declaredType : existingType,
187:     );
188:     if (assignResult instanceof Err) return assignResult;
189: 
190:     // Record this variable's effective type for later lookups only if not already known
191:     const resolvedType = declaredType ?? srcType ?? "";
192:     if (resolvedType.length > 0 && existingType === undefined) {
193:       allVarTypes.push({ name: varName, type: resolvedType });
194:     }
195: 
196:     // Use 'let' for mutable vars, 'const' otherwise; bare reassignments omit the keyword
197:     code +=
198:       (isMutable ? "let" : existingType !== undefined ? "" : constKeyword) +
199:       varName +
200:       " = " +
201:       (() => {
202:         const prefix = "if (";
203:         const idx = value.indexOf(prefix);
204:         if (idx !== 0) return value;
205:         const conditionStart = idx + prefix.length;
206:         let depth = 0;
207:         let condEnd = -1;
208:         for (let i = conditionStart - 1; i < value.length; i++) {
209:           const ch = value[i];
210:           if (ch === "(") depth++;
211:           else if (ch === ")") {
212:             depth--;
213:             if (depth === 0) {
214:               condEnd = i;
215:               break;
216:             }
217:           }
218:         }
219:         if (condEnd === -1) return value;
220:         const rest = value.substring(condEnd + 1).trim();
221:         for (let i = 0; i < rest.length - 3; i++) {
222:           if (rest.substring(i, i + 4) === "else") {
223:             return (
224:               "(" +
225:               value.substring(conditionStart, condEnd) +
226:               ") ? (" +
227:               rest.substring(0, i).trim() +
228:               ") : (" +
229:               rest.substring(i + 4).trim() +
230:               ")"
231:             );
232:           }
233:         }
234:         return value;
235:       })() +
236:       "\n";
237:     return okVoid;
238:   }
