240:  // Helper: detect if an expression contains comparison operators (<, >, <=, >=, ==, !=)
241:   function isComparisonExpr(expr: string): boolean {
242:     return (
243:       expr.includes("<") ||
244:       expr.includes(">") ||
245:       expr.includes("==") ||
246:       expr.includes("!=")
247:     );
248:   }
