250:   // Helper: parse and emit a `let` declaration from the text after "let"
251:   function processLetDecl(restOfDeclInput: string): Ok<void> | Err<CompileError> {
252:     let rest = restOfDeclInput;
253:     let isMutable = false;
254:     if (rest.startsWith("mut ")) {
255:       isMutable = true;
256:       rest = rest.substring(4);
257:     }
258: 
259:     let varName: string;
260:     let declaredType: string | undefined;
261:     const colonPos = rest.indexOf(":");
262:     const eqPos = rest.indexOf("=");
263: 
264:     if (colonPos !== -1) {
265:       varName = rest.substring(0, colonPos).trim();
266:       declaredType = rest
267:         .substring(colonPos + 1, eqPos >= 0 ? eqPos : rest.length)
268:         .trim();
269:     } else {
270:       varName = rest.substring(0, eqPos).trim();
271:     }
272: 
273:     if (declaredVars.indexOf(varName) !== -1) {
274:       return new Err(CompileError.DuplicateVariable);
275:     }
276:     declaredVars.push(varName);
277: 
278:     if (isMutable) {
279:       mutVars.add(varName);
280:     }
281: 
282:     if (eqPos >= 0) {
283:       const assignResult = emitAssignment(
284:         varName,
285:         rest.substring(eqPos + 1).trim(),
286:         declaredType,
287:         isMutable,
288:       );
289:       if (assignResult instanceof Err) return assignResult;
290:     }
291: 
292:     return okVoid;
293:   }
