295:   // Helper: emit a return statement with bool conversion when needed
296:   function emitReturn(retExpr: string): void {
297:     if (
298:       retExpr === boolTrue ||
299:       retExpr === boolFalse ||
300:       lookupType(retExpr) === "Bool" ||
301:       retExpr.includes("||") ||
302:       retExpr.includes("&&") ||
303:       isComparisonExpr(retExpr)
304:     ) {
305:       code += returnStr + "(+(" + retExpr + "))\n";
306:     } else {
307:       code += returnStr + retExpr + "\n";
308:     }
309:   }
